const staticData = $getWorkflowStaticData('global');
if (!staticData.auto_respond) staticData.auto_respond = 'on';
if (!staticData.notify_filter) staticData.notify_filter = 'all';

const previousData = $input.all()[0].json;
const category = (previousData['Тип звонка(Category)'] || previousData.category || '').toLowerCase();
const filter = staticData.notify_filter;

let shouldNotify = true;
if (filter === 'all') {
  shouldNotify = true;
} else if (filter.includes(',')) {
  shouldNotify = filter.split(',').includes(category);
} else {
  shouldNotify = filter === category;
}

return [{
  json: {
    ...previousData,
    auto_respond: staticData.auto_respond,
    should_notify: shouldNotify
  }
}];

const staticData = $getWorkflowStaticData('global');
const text = $json.message.text.trim();
const chatId = $json.message.chat.id;

if (!staticData.auto_respond) staticData.auto_respond = 'on';
if (!staticData.notify_filter) staticData.notify_filter = 'all';

let responseText = '';

if (text === '/on') {
  staticData.auto_respond = 'on';
  responseText = '⚙️ Автоответ: ВКЛЮЧЁН ✅\n\nКлиенты будут получать ответ автоматически.';

} else if (text === '/off') {
  staticData.auto_respond = 'off';
  responseText = '⚙️ Автоответ: ВЫКЛЮЧЕН 🔴\n\nВы будете получать уведомления с кнопками для одобрения.';

} else if (text === '/status') {
  const mode = staticData.auto_respond === 'on' ? '✅ ВКЛЮЧЁН' : '🔴 ВЫКЛЮЧЕН';
  const filter = staticData.notify_filter;
  responseText = '⚙️ Текущие настройки:\n\n📨 Автоответ: ' + mode + '\n🔔 Фильтр: ' + filter;

} else if (text.startsWith('/filter_')) {
  const filter = text.replace('/filter_', '').toLowerCase().trim();
  if (['hot', 'warm', 'cold', 'hot_warm', 'all'].includes(filter)) {
    const saveFilter = filter.replace('_', ',');
    staticData.notify_filter = saveFilter;
    responseText = '🔔 Фильтр уведомлений: ' + saveFilter;
  } else {
    responseText = '❓ Неверный фильтр.\n/filter_hot\n/filter_hot_warm\n/filter_all';
  }

} else {
  responseText = '❓ Неизвестная команда.\n\n/on — включить автоответ\n/off — выключить автоответ\n/status — настройки\n/analytics — аналитика\n/filter_hot — только горячие\n/filter_hot_warm — горячие и тёплые\n/filter_all — все';
}

return [{
  json: {
    chat_id: chatId,
    response_text: responseText
  }
}];

