const geminiResponse = $input.first().json.content.parts[0].text.trim().toLowerCase();
const telegramData = $('Telegram Trigger').first().json;

const intent = geminiResponse.includes('lead') ? 'lead' : 'question';

return [{
  json: {
    intent: intent,
    message_text: telegramData.message.text,
    chat_id: telegramData.message.chat.id,
    first_name: telegramData.message.from.first_name,
    username: telegramData.message.from.username
  }
}];

const rows = $input.all().map(item => item.json);
const telegramData = $('Telegram Trigger').first().json;

const now = new Date();
const todayStr = now.toISOString().split('T')[0];
const yesterday = new Date(now);
yesterday.setDate(yesterday.getDate() - 1);
const yesterdayStr = yesterday.toISOString().split('T')[0];

const recentRows = rows.filter(row => {
  const ts = row.Timestamp || '';
  return ts.startsWith(todayStr) || ts.startsWith(yesterdayStr);
});

// Course detection by keywords
const courseKeywords = {
  'Unity 3D': ['unity', 'юнити', 'game dev', 'gamedev', 'разработка игр'],
  'Unreal Engine': ['unreal', 'анрил', 'ue5', 'ue4'],
  'UI/UX дизайн': ['ui/ux', 'ui ux', 'uiux', 'дизайн', 'figma', 'ux design'],
  '3D моделирование': ['3d', 'blender', 'maya', 'моделирование', 'анимация'],
  'Product Management': ['product management', 'продакт', 'менеджмент продукта'],
  'AR/VR': ['ar/vr', 'ar vr', 'arvr', 'дополненная реальность', 'виртуальная реальность'],
  'Data Science / ML': ['data science', 'ds', 'machine learning', 'ml', 'python', 'питон']
};

function detectCourse(message) {
  const lower = (message || '').toLowerCase();
  for (const [course, keywords] of Object.entries(courseKeywords)) {
    for (const kw of keywords) {
      if (lower.includes(kw)) return course;
    }
  }
  return 'Другое';
}

let totalHot = 0, totalWarm = 0, totalCold = 0;
for (const row of rows) {
  const cat = (row['Тип звонка(Category)'] || '').toLowerCase();
  if (cat === 'hot') totalHot++;
  else if (cat === 'warm') totalWarm++;
  else if (cat === 'cold') totalCold++;
}

let recentHot = 0, recentWarm = 0, recentCold = 0;
const courseCounts = {};
const companies = {};

for (const row of recentRows) {
  const cat = (row['Тип звонка(Category)'] || '').toLowerCase();
  if (cat === 'hot') recentHot++;
  else if (cat === 'warm') recentWarm++;
  else if (cat === 'cold') recentCold++;

  const course = detectCourse(row.Message);
  courseCounts[course] = (courseCounts[course] || 0) + 1;

  const company = row.Company || '';
  if (company && company !== 'null' && company !== '') {
    companies[company] = (companies[company] || 0) + 1;
  }
}

const topCourses = Object.entries(courseCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map((c, i) => `${i + 1}. ${c[0]} — ${c[1]}`)
  .join('\n');

const topCompanies = Object.entries(companies)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map((c, i) => `${i + 1}. ${c[0]} — ${c[1]}`)
  .join('\n');

const report = `📊 Аналитика

📅 За последние 2 дня:
📥 Лидов: ${recentRows.length}
🔥 Hot: ${recentHot} | 🟡 Warm: ${recentWarm} | 🔵 Cold: ${recentCold}

📅 За всё время:
📥 Лидов: ${rows.length}
🔥 Hot: ${totalHot} | 🟡 Warm: ${totalWarm} | 🔵 Cold: ${totalCold}

🏆 Топ курсы (2 дня):
${topCourses || 'Нет данных'}

🏢 Топ компании (2 дня):
${topCompanies || 'Нет данных'}`;

return [{
  json: {
    chat_id: telegramData.message.chat.id,
    report: report
  }
}];

